/* =============================================
   NAC Cafe - News Portal Stylesheet
   Premium warm café & news portal theme
   ============================================= */

/* ---------- CSS Variables ---------- */
:root {
    --primary: #5D4037;
    --primary-dark: #3E2723;
    --primary-light: #8D6E63;
    --primary-rgb: 93, 64, 55;
    --accent: #D4920B;
    --accent-light: #F5B731;
    --accent-dark: #B07A09;
    --accent-rgb: 212, 146, 11;
    --bg-cream: #FAF6F1;
    --bg-warm: #F5EDE4;
    --bg-white: #FFFFFF;
    --bg-dark: #1C120D;
    --bg-dark-card: #2A1F18;
    --text-dark: #1A120D;
    --text-body: #4A3F38;
    --text-light: #8C7B70;
    --text-white: #FFFFFF;
    --border: #E8DDD3;
    --border-light: #F0E8DE;
    --shadow-xs: 0 1px 3px rgba(var(--primary-rgb), 0.04);
    --shadow: 0 2px 12px rgba(var(--primary-rgb), 0.06);
    --shadow-md: 0 8px 30px rgba(var(--primary-rgb), 0.1);
    --shadow-lg: 0 16px 50px rgba(var(--primary-rgb), 0.14);
    --shadow-xl: 0 24px 60px rgba(var(--primary-rgb), 0.18);
    --shadow-accent: 0 6px 24px rgba(var(--accent-rgb), 0.25);
    --radius: 10px;
    --radius-md: 14px;
    --radius-lg: 20px;
    --radius-xl: 28px;
    --transition: 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    --transition-slow: 0.5s cubic-bezier(0.4, 0, 0.2, 1);
    --max-width: 1200px;
    --header-height: 76px;
    --font-sans: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
    --font-serif: 'Playfair Display', Georgia, 'Times New Roman', serif;
}

/* ---------- Reset & Base ---------- */
*, *::before, *::after {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html {
    scroll-behavior: smooth;
    font-size: 16px;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
}

body {
    font-family: var(--font-sans);
    background: var(--bg-cream);
    color: var(--text-body);
    line-height: 1.7;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    overflow-x: hidden;
}

::selection {
    background: var(--accent);
    color: var(--text-white);
}

a {
    color: var(--primary);
    text-decoration: none;
    transition: color var(--transition);
}
a:hover { color: var(--accent); }

img {
    max-width: 100%;
    height: auto;
    display: block;
}

h1, h2, h3, h4, h5 {
    font-family: var(--font-serif);
    color: var(--text-dark);
    line-height: 1.25;
    font-weight: 700;
}

.container {
    width: 100%;
    max-width: var(--max-width);
    margin: 0 auto;
    padding: 0 24px;
}

/* ---------- Animations ---------- */
@keyframes fadeInUp {
    from { opacity: 0; transform: translateY(24px); }
    to { opacity: 1; transform: translateY(0); }
}
@keyframes fadeIn {
    from { opacity: 0; }
    to { opacity: 1; }
}
@keyframes slideDown {
    from { opacity: 0; transform: translateY(-12px); }
    to { opacity: 1; transform: translateY(0); }
}
@keyframes float {
    0%, 100% { transform: translateY(0px); }
    50% { transform: translateY(-6px); }
}

.animate-in {
    animation: fadeInUp 0.6s ease both;
}

/* ---------- Header ---------- */
.site-header {
    background: rgba(255, 255, 255, 0.92);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    border-bottom: 1px solid rgba(var(--primary-rgb), 0.06);
    position: sticky;
    top: 0;
    z-index: 1000;
    transition: box-shadow var(--transition);
}
.site-header:hover {
    box-shadow: var(--shadow-md);
}

.header-inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: var(--header-height);
}

.logo a {
    display: flex;
    align-items: center;
    gap: 10px;
    text-decoration: none;
}

.logo-icon {
    font-size: 32px;
    filter: drop-shadow(0 2px 4px rgba(var(--primary-rgb), 0.2));
    animation: float 3s ease-in-out infinite;
}

.logo-text {
    font-family: var(--font-serif);
    font-size: 26px;
    font-weight: 700;
    color: var(--primary-dark);
    letter-spacing: -0.5px;
}

.logo-accent {
    color: var(--accent);
    position: relative;
}
.logo-accent::after {
    content: '';
    position: absolute;
    bottom: 2px;
    left: 0;
    right: 0;
    height: 3px;
    background: var(--accent);
    border-radius: 2px;
    opacity: 0.3;
}

.tagline {
    font-size: 11px;
    color: var(--text-light);
    margin-top: -4px;
    letter-spacing: 1px;
    text-transform: uppercase;
    font-weight: 500;
}

.main-nav ul {
    display: flex;
    list-style: none;
    gap: 2px;
    align-items: center;
}

.main-nav a {
    padding: 10px 18px;
    border-radius: 50px;
    font-weight: 500;
    font-size: 14px;
    color: var(--text-body);
    transition: all var(--transition);
    position: relative;
}

.main-nav a:hover {
    color: var(--primary);
    background: var(--bg-warm);
}

.main-nav a.active {
    color: var(--primary-dark);
    background: var(--bg-warm);
    font-weight: 600;
}
.main-nav a.active::after {
    content: '';
    position: absolute;
    bottom: 4px;
    left: 50%;
    transform: translateX(-50%);
    width: 20px;
    height: 3px;
    background: var(--accent);
    border-radius: 2px;
}

.btn-nav {
    background: linear-gradient(135deg, var(--primary), var(--primary-dark)) !important;
    color: var(--text-white) !important;
    padding: 10px 24px !important;
    border-radius: 50px !important;
    font-weight: 600 !important;
    box-shadow: 0 4px 16px rgba(var(--primary-rgb), 0.25) !important;
    transition: all var(--transition) !important;
}
.btn-nav:hover {
    background: linear-gradient(135deg, var(--primary-dark), #2A1810) !important;
    color: var(--text-white) !important;
    transform: translateY(-1px) !important;
    box-shadow: 0 6px 20px rgba(var(--primary-rgb), 0.35) !important;
}

.mobile-toggle {
    display: none;
    flex-direction: column;
    gap: 5px;
    background: none;
    border: none;
    cursor: pointer;
    padding: 8px;
    border-radius: var(--radius);
    transition: background var(--transition);
}
.mobile-toggle:hover {
    background: var(--bg-warm);
}
.mobile-toggle span {
    display: block;
    width: 22px;
    height: 2px;
    background: var(--primary-dark);
    transition: var(--transition);
    border-radius: 2px;
}

/* ---------- Main Content ---------- */
.site-main {
    flex: 1;
    padding: 48px 0;
}

/* ---------- Hero Section ---------- */
.hero {
    background: 
        linear-gradient(135deg, rgba(28, 18, 13, 0.92) 0%, rgba(62, 39, 35, 0.88) 50%, rgba(93, 64, 55, 0.85) 100%);
    color: var(--text-white);
    padding: 100px 0;
    margin: -48px 0 48px;
    text-align: center;
    position: relative;
    overflow: hidden;
}
.hero::before {
    content: '';
    position: absolute;
    top: -50%;
    left: -50%;
    width: 200%;
    height: 200%;
    background: radial-gradient(circle at 30% 50%, rgba(212, 146, 11, 0.08) 0%, transparent 50%),
                radial-gradient(circle at 70% 80%, rgba(255, 255, 255, 0.03) 0%, transparent 40%);
    pointer-events: none;
}
.hero::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    height: 80px;
    background: linear-gradient(to top, var(--bg-cream), transparent);
    pointer-events: none;
}

.hero .container {
    position: relative;
    z-index: 1;
}

.hero h1 {
    font-size: 48px;
    color: var(--text-white);
    margin-bottom: 16px;
    animation: fadeInUp 0.8s ease both;
    letter-spacing: -1px;
}

.hero p {
    font-size: 18px;
    opacity: 0.85;
    max-width: 560px;
    margin: 0 auto;
    animation: fadeInUp 0.8s ease 0.15s both;
    line-height: 1.8;
}

.hero .btn-primary {
    margin-top: 32px;
    display: inline-block;
    animation: fadeInUp 0.8s ease 0.3s both;
    padding: 16px 36px;
    font-size: 15px;
}

/* ---------- Buttons ---------- */
.btn-primary {
    display: inline-block;
    background: linear-gradient(135deg, var(--accent), var(--accent-dark));
    color: var(--text-white);
    padding: 13px 30px;
    border-radius: 50px;
    font-weight: 600;
    font-size: 14px;
    border: none;
    cursor: pointer;
    transition: all var(--transition);
    text-align: center;
    box-shadow: 0 4px 16px rgba(var(--accent-rgb), 0.3);
    letter-spacing: 0.2px;
    position: relative;
    overflow: hidden;
}
.btn-primary::before {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 100%;
    height: 100%;
    background: linear-gradient(90deg, transparent, rgba(255,255,255,0.15), transparent);
    transition: left 0.5s;
}
.btn-primary:hover::before {
    left: 100%;
}
.btn-primary:hover {
    background: linear-gradient(135deg, var(--accent-light), var(--accent));
    color: var(--text-white);
    transform: translateY(-2px);
    box-shadow: 0 8px 28px rgba(var(--accent-rgb), 0.4);
}
.btn-primary:active {
    transform: translateY(0);
}

.btn-secondary {
    display: inline-block;
    background: transparent;
    color: var(--primary);
    padding: 13px 30px;
    border-radius: 50px;
    font-weight: 600;
    font-size: 14px;
    border: 2px solid var(--primary);
    cursor: pointer;
    transition: all var(--transition);
    position: relative;
    overflow: hidden;
}
.btn-secondary::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 0;
    height: 100%;
    background: var(--primary);
    transition: width var(--transition);
    z-index: -1;
}
.btn-secondary:hover::before {
    width: 100%;
}
.btn-secondary:hover {
    color: var(--text-white);
    border-color: var(--primary);
}

.btn-danger {
    background: linear-gradient(135deg, #C62828, #B71C1C);
    color: white;
    padding: 11px 24px;
    border-radius: 50px;
    border: none;
    cursor: pointer;
    font-weight: 600;
    transition: all var(--transition);
    box-shadow: 0 4px 16px rgba(198, 40, 40, 0.25);
}
.btn-danger:hover { 
    background: linear-gradient(135deg, #B71C1C, #8E0000);
    transform: translateY(-1px);
}

.btn-small {
    padding: 7px 16px;
    font-size: 13px;
}

/* ---------- Cards ---------- */
.card {
    background: var(--bg-white);
    border-radius: var(--radius-lg);
    overflow: hidden;
    box-shadow: var(--shadow);
    transition: all var(--transition);
    border: 1px solid rgba(var(--primary-rgb), 0.04);
}
.card:hover {
    box-shadow: var(--shadow-lg);
    transform: translateY(-6px);
    border-color: rgba(var(--accent-rgb), 0.15);
}

.card-image {
    width: 100%;
    height: 220px;
    background: linear-gradient(135deg, var(--primary), var(--primary-dark));
    display: flex;
    align-items: center;
    justify-content: center;
    color: white;
    font-size: 48px;
    position: relative;
    overflow: hidden;
}
.card-image::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: linear-gradient(135deg, transparent 40%, rgba(255,255,255,0.05) 100%);
}
.card-image::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    height: 60px;
    background: linear-gradient(to top, rgba(0,0,0,0.15), transparent);
}

.card-body {
    padding: 24px;
}

.card-body h3 {
    font-size: 18px;
    margin-bottom: 10px;
    transition: color var(--transition);
    line-height: 1.4;
}
.card:hover .card-body h3 {
    color: var(--accent-dark);
}

.card-body p {
    color: var(--text-light);
    font-size: 14px;
    margin-bottom: 14px;
    line-height: 1.7;
    display: -webkit-box;
    -webkit-line-clamp: 3;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.card-meta {
    display: flex;
    justify-content: space-between;
    align-items: center;
    font-size: 12px;
    color: var(--text-light);
    padding-top: 14px;
    border-top: 1px solid var(--border-light);
}

.card-category {
    display: inline-block;
    background: linear-gradient(135deg, var(--bg-warm), var(--bg-cream));
    color: var(--primary);
    padding: 5px 14px;
    border-radius: 50px;
    font-size: 12px;
    font-weight: 600;
    letter-spacing: 0.3px;
    text-transform: uppercase;
    margin-bottom: 8px;
}

/* ---------- Articles Grid ---------- */
.articles-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(340px, 1fr));
    gap: 28px;
}

.featured-article {
    grid-column: 1 / -1;
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 0;
    border-radius: var(--radius-xl);
    overflow: hidden;
    background: var(--bg-white);
    box-shadow: var(--shadow-md);
    border: 1px solid rgba(var(--primary-rgb), 0.04);
    transition: all var(--transition);
}
.featured-article:hover {
    box-shadow: var(--shadow-xl);
    transform: translateY(-4px);
}

.featured-article .card-image {
    height: 100%;
    min-height: 340px;
    font-size: 72px;
}

.featured-article .card-body {
    padding: 40px;
    display: flex;
    flex-direction: column;
    justify-content: center;
}

.featured-article h3 {
    font-size: 28px;
    margin-bottom: 14px;
    letter-spacing: -0.5px;
}

.featured-article p {
    font-size: 15px;
    line-height: 1.9;
}

/* ---------- Article Detail ---------- */
.article-detail {
    max-width: 800px;
    margin: 0 auto;
}

.article-header {
    text-align: center;
    margin-bottom: 36px;
    animation: fadeInUp 0.6s ease both;
}

.article-header h1 {
    font-size: 38px;
    margin-bottom: 18px;
    letter-spacing: -0.5px;
    line-height: 1.3;
}

.article-meta {
    display: flex;
    justify-content: center;
    gap: 24px;
    color: var(--text-light);
    font-size: 14px;
    flex-wrap: wrap;
}
.article-meta span {
    display: flex;
    align-items: center;
    gap: 4px;
}

.article-content {
    background: var(--bg-white);
    padding: 48px;
    border-radius: var(--radius-xl);
    box-shadow: var(--shadow-md);
    line-height: 1.9;
    font-size: 16.5px;
    border: 1px solid rgba(var(--primary-rgb), 0.04);
    animation: fadeInUp 0.6s ease 0.15s both;
}

.article-content p {
    margin-bottom: 20px;
}

.article-content ul, .article-content ol {
    padding-left: 28px;
    margin-bottom: 20px;
}

.article-content li {
    margin-bottom: 10px;
}

.article-content strong {
    color: var(--text-dark);
}

.article-content em {
    color: var(--primary);
}

/* ---------- Comments ---------- */
.comments-section {
    max-width: 800px;
    margin: 48px auto 0;
    animation: fadeInUp 0.6s ease 0.3s both;
}

.comments-section h3 {
    font-size: 22px;
    margin-bottom: 24px;
    padding-bottom: 14px;
    border-bottom: 2px solid var(--border);
    display: flex;
    align-items: center;
    gap: 8px;
}

.comment {
    background: var(--bg-white);
    padding: 24px;
    border-radius: var(--radius-md);
    margin-bottom: 16px;
    box-shadow: var(--shadow);
    border: 1px solid rgba(var(--primary-rgb), 0.03);
    transition: all var(--transition);
}
.comment:hover {
    box-shadow: var(--shadow-md);
    border-color: rgba(var(--primary-rgb), 0.08);
}

.comment-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 10px;
}

.comment-author {
    font-weight: 600;
    color: var(--primary);
    font-size: 15px;
}

.comment-date {
    font-size: 12px;
    color: var(--text-light);
}

.comment-content {
    font-size: 14px;
    line-height: 1.7;
    color: var(--text-body);
}

.comment-form {
    background: var(--bg-white);
    padding: 28px;
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow-md);
    margin-bottom: 24px;
    border: 1px solid rgba(var(--primary-rgb), 0.04);
}

.comment-form h4 {
    margin-bottom: 18px;
    font-size: 18px;
}

/* ---------- Menu Page ---------- */
.menu-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
    gap: 24px;
}

.menu-card {
    background: var(--bg-white);
    border-radius: var(--radius-lg);
    overflow: hidden;
    box-shadow: var(--shadow);
    transition: all var(--transition);
    border: 1px solid rgba(var(--primary-rgb), 0.04);
}
.menu-card:hover {
    box-shadow: var(--shadow-lg);
    transform: translateY(-4px);
    border-color: rgba(var(--accent-rgb), 0.15);
}

.menu-card-image {
    width: 100%;
    height: 170px;
    background: linear-gradient(135deg, var(--primary-light), var(--accent));
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 42px;
    position: relative;
    overflow: hidden;
}
.menu-card-image::before {
    content: '';
    position: absolute;
    top: -50%;
    right: -50%;
    width: 100%;
    height: 100%;
    background: radial-gradient(circle, rgba(255,255,255,0.12), transparent 60%);
}

.menu-card-body {
    padding: 20px;
}

.menu-card-body h3 {
    font-size: 17px;
    margin-bottom: 6px;
    font-family: var(--font-sans);
    font-weight: 600;
}

.menu-card-body p {
    font-size: 13px;
    color: var(--text-light);
    margin-bottom: 12px;
    line-height: 1.6;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.menu-price {
    font-family: var(--font-serif);
    font-size: 20px;
    font-weight: 700;
    color: var(--accent-dark);
    display: flex;
    align-items: center;
    gap: 4px;
}

.menu-category-title {
    font-size: 30px;
    margin: 48px 0 24px;
    padding-bottom: 12px;
    border-bottom: 3px solid var(--accent);
    display: inline-block;
    position: relative;
}

/* ---------- Forms ---------- */
.form-group {
    margin-bottom: 22px;
}

.form-group label {
    display: block;
    font-weight: 600;
    margin-bottom: 8px;
    color: var(--text-dark);
    font-size: 14px;
}

.form-group input,
.form-group textarea,
.form-group select {
    width: 100%;
    padding: 14px 18px;
    border: 2px solid var(--border);
    border-radius: var(--radius-md);
    font-family: inherit;
    font-size: 14px;
    transition: all var(--transition);
    background: var(--bg-white);
    color: var(--text-dark);
}

.form-group input:focus,
.form-group textarea:focus,
.form-group select:focus {
    outline: none;
    border-color: var(--primary);
    box-shadow: 0 0 0 4px rgba(var(--primary-rgb), 0.08);
    background: var(--bg-white);
}

.form-group input::placeholder,
.form-group textarea::placeholder {
    color: var(--text-light);
    opacity: 0.7;
}

.form-group textarea {
    min-height: 130px;
    resize: vertical;
    line-height: 1.7;
}

/* ---------- Auth Pages ---------- */
.auth-container {
    max-width: 460px;
    margin: 0 auto;
    animation: fadeInUp 0.6s ease both;
}

.auth-box {
    background: var(--bg-white);
    padding: 48px;
    border-radius: var(--radius-xl);
    box-shadow: var(--shadow-lg);
    border: 1px solid rgba(var(--primary-rgb), 0.04);
    position: relative;
    overflow: hidden;
}
.auth-box::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 4px;
    background: linear-gradient(90deg, var(--primary), var(--accent), var(--primary));
}

.auth-box h2 {
    text-align: center;
    margin-bottom: 8px;
    font-size: 30px;
}

.auth-box .subtitle {
    text-align: center;
    color: var(--text-light);
    margin-bottom: 32px;
    font-size: 14px;
}

.auth-links {
    text-align: center;
    margin-top: 24px;
    font-size: 14px;
    color: var(--text-light);
}
.auth-links a {
    font-weight: 600;
    color: var(--accent-dark);
}
.auth-links a:hover {
    color: var(--accent);
}

/* ---------- Profile Page ---------- */
.profile-container {
    max-width: 800px;
    margin: 0 auto;
    animation: fadeInUp 0.6s ease both;
}

.profile-header {
    background: linear-gradient(135deg, var(--primary-dark) 0%, var(--primary) 60%, var(--primary-light) 100%);
    color: white;
    padding: 48px 40px;
    border-radius: var(--radius-xl) var(--radius-xl) 0 0;
    text-align: center;
    position: relative;
    overflow: hidden;
}
.profile-header::before {
    content: '';
    position: absolute;
    top: -50%;
    right: -30%;
    width: 60%;
    height: 200%;
    background: radial-gradient(circle, rgba(255,255,255,0.05), transparent 60%);
}

.profile-header h2 {
    color: white;
    margin-bottom: 6px;
    font-size: 26px;
}
.profile-header p {
    opacity: 0.8;
    font-size: 14px;
}

.profile-avatar {
    width: 88px;
    height: 88px;
    border-radius: 50%;
    background: linear-gradient(135deg, var(--accent), var(--accent-light));
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto 18px;
    font-size: 34px;
    color: white;
    border: 4px solid rgba(255,255,255,0.3);
    box-shadow: 0 8px 24px rgba(0,0,0,0.2);
    font-weight: 700;
}

.profile-body {
    background: var(--bg-white);
    padding: 40px;
    border-radius: 0 0 var(--radius-xl) var(--radius-xl);
    box-shadow: var(--shadow-md);
    border: 1px solid rgba(var(--primary-rgb), 0.04);
    border-top: none;
}

.profile-info {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 4px;
}

.profile-field {
    padding: 16px;
    border-radius: var(--radius);
    transition: background var(--transition);
}
.profile-field:hover {
    background: var(--bg-cream);
}

.profile-field label {
    display: block;
    font-size: 11px;
    font-weight: 700;
    color: var(--text-light);
    text-transform: uppercase;
    letter-spacing: 0.8px;
    margin-bottom: 6px;
}

.profile-field span {
    font-size: 15px;
    color: var(--text-dark);
    font-weight: 500;
}

.loyalty-section {
    margin-top: 36px;
    padding: 32px;
    background: linear-gradient(135deg, var(--bg-warm), var(--bg-cream));
    border-radius: var(--radius-lg);
    text-align: center;
    border: 1px solid var(--border);
}

.loyalty-points {
    font-family: var(--font-serif);
    font-size: 52px;
    font-weight: 700;
    color: var(--accent-dark);
    line-height: 1;
    margin: 8px 0;
}

.loyalty-label {
    color: var(--text-light);
    font-size: 14px;
    font-weight: 500;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

/* ---------- Search ---------- */
.search-container {
    max-width: 800px;
    margin: 0 auto;
    animation: fadeInUp 0.6s ease both;
}

.search-box {
    display: flex;
    gap: 12px;
    margin-bottom: 36px;
}

.search-box input {
    flex: 1;
    padding: 16px 24px;
    border: 2px solid var(--border);
    border-radius: 50px;
    font-size: 16px;
    transition: all var(--transition);
    background: var(--bg-white);
}

.search-box input:focus {
    border-color: var(--primary);
    outline: none;
    box-shadow: 0 0 0 4px rgba(var(--primary-rgb), 0.08);
}

.search-box .btn-primary {
    min-width: 120px;
}

.search-results {
    margin-top: 28px;
}

.search-result-item {
    background: var(--bg-white);
    padding: 24px;
    border-radius: var(--radius-md);
    margin-bottom: 16px;
    box-shadow: var(--shadow);
    border: 1px solid rgba(var(--primary-rgb), 0.04);
    transition: all var(--transition);
}
.search-result-item:hover {
    box-shadow: var(--shadow-md);
    transform: translateX(4px);
    border-color: rgba(var(--primary-rgb), 0.08);
}

.search-result-item h3 {
    margin-bottom: 8px;
    font-size: 18px;
}

.search-result-item p {
    color: var(--text-light);
    font-size: 14px;
    line-height: 1.7;
}

/* ---------- Contact ---------- */
.contact-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 32px;
    max-width: 920px;
    margin: 0 auto;
    animation: fadeInUp 0.6s ease both;
}

.contact-info {
    padding: 36px;
    background: var(--bg-white);
    border-radius: var(--radius-xl);
    box-shadow: var(--shadow-md);
    border: 1px solid rgba(var(--primary-rgb), 0.04);
}

.contact-info h3 {
    margin-bottom: 24px;
    font-size: 22px;
}

.contact-item {
    display: flex;
    gap: 16px;
    margin-bottom: 24px;
    align-items: flex-start;
}

.contact-icon {
    font-size: 22px;
    min-width: 44px;
    height: 44px;
    display: flex;
    align-items: center;
    justify-content: center;
    background: var(--bg-warm);
    border-radius: var(--radius);
    flex-shrink: 0;
}

.contact-form-box {
    background: var(--bg-white);
    padding: 36px;
    border-radius: var(--radius-xl);
    box-shadow: var(--shadow-md);
    border: 1px solid rgba(var(--primary-rgb), 0.04);
}

/* ---------- Admin Pages ---------- */
.admin-layout {
    display: grid;
    grid-template-columns: 260px 1fr;
    gap: 0;
    min-height: calc(100vh - var(--header-height));
    margin: -48px 0;
}

.admin-sidebar {
    background: linear-gradient(180deg, var(--bg-dark) 0%, #241810 100%);
    padding: 28px 0;
    color: var(--text-white);
    position: sticky;
    top: var(--header-height);
    height: calc(100vh - var(--header-height));
    overflow-y: auto;
}

.admin-sidebar h3 {
    color: var(--accent);
    font-size: 17px;
    padding: 0 24px;
    margin-bottom: 24px;
    font-family: var(--font-serif);
}

.admin-sidebar ul {
    list-style: none;
}

.admin-sidebar a {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 13px 24px;
    color: rgba(255,255,255,0.55);
    font-size: 14px;
    transition: all var(--transition);
    border-left: 3px solid transparent;
    font-weight: 500;
}

.admin-sidebar a:hover {
    background: rgba(255,255,255,0.06);
    color: rgba(255,255,255,0.9);
    border-left-color: rgba(255,255,255,0.2);
}

.admin-sidebar a.active {
    background: rgba(var(--accent-rgb), 0.1);
    color: var(--accent-light);
    border-left-color: var(--accent);
}

.admin-content {
    padding: 36px;
    background: var(--bg-cream);
}

.admin-header {
    margin-bottom: 32px;
}

.admin-header h2 {
    font-size: 30px;
    margin-bottom: 6px;
    letter-spacing: -0.5px;
}

.admin-header p {
    color: var(--text-light);
    font-size: 15px;
}

.stat-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 20px;
    margin-bottom: 36px;
}

.stat-card {
    background: var(--bg-white);
    padding: 28px;
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow);
    text-align: center;
    border: 1px solid rgba(var(--primary-rgb), 0.04);
    transition: all var(--transition);
    position: relative;
    overflow: hidden;
}
.stat-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 3px;
    background: linear-gradient(90deg, var(--primary), var(--accent));
    opacity: 0;
    transition: opacity var(--transition);
}
.stat-card:hover::before {
    opacity: 1;
}
.stat-card:hover {
    box-shadow: var(--shadow-md);
    transform: translateY(-2px);
}

.stat-value {
    font-family: var(--font-serif);
    font-size: 36px;
    font-weight: 700;
    color: var(--primary);
    line-height: 1;
}

.stat-label {
    font-size: 13px;
    color: var(--text-light);
    margin-top: 8px;
    font-weight: 500;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.admin-table {
    width: 100%;
    background: var(--bg-white);
    border-radius: var(--radius-md);
    overflow: hidden;
    box-shadow: var(--shadow);
    border-collapse: collapse;
    border: 1px solid rgba(var(--primary-rgb), 0.04);
}

.admin-table th {
    background: linear-gradient(135deg, var(--primary-dark), var(--primary));
    color: white;
    padding: 14px 18px;
    text-align: left;
    font-size: 13px;
    font-weight: 600;
    letter-spacing: 0.3px;
    text-transform: uppercase;
}

.admin-table td {
    padding: 14px 18px;
    border-bottom: 1px solid var(--border-light);
    font-size: 14px;
}

.admin-table tr {
    transition: background var(--transition);
}
.admin-table tr:hover {
    background: var(--bg-cream);
}

.admin-table tr:last-child td {
    border-bottom: none;
}

/* ---------- Alerts ---------- */
.alert {
    padding: 16px 22px;
    border-radius: var(--radius-md);
    margin-bottom: 20px;
    font-size: 14px;
    font-weight: 500;
    display: flex;
    align-items: center;
    gap: 10px;
    border: 1px solid;
}

.alert-success {
    background: #F0F9F0;
    color: #1B5E20;
    border-color: #A5D6A7;
}

.alert-error {
    background: #FFF5F5;
    color: #B71C1C;
    border-color: #EF9A9A;
}

.alert-warning {
    background: #FFFAF0;
    color: #E65100;
    border-color: #FFCC80;
}

.alert-info {
    background: #F0F7FF;
    color: #0D47A1;
    border-color: #90CAF9;
}

/* ---------- Pagination ---------- */
.pagination {
    display: flex;
    justify-content: center;
    gap: 6px;
    margin-top: 40px;
}

.pagination a, .pagination span {
    padding: 10px 16px;
    border-radius: var(--radius);
    font-size: 14px;
    border: 1px solid var(--border);
    background: var(--bg-white);
    font-weight: 500;
    transition: all var(--transition);
    min-width: 42px;
    text-align: center;
}

.pagination a:hover {
    background: var(--primary);
    color: white;
    border-color: var(--primary);
    transform: translateY(-1px);
    box-shadow: 0 4px 12px rgba(var(--primary-rgb), 0.2);
}

.pagination .current {
    background: linear-gradient(135deg, var(--primary), var(--primary-dark));
    color: white;
    border-color: var(--primary);
    box-shadow: 0 4px 12px rgba(var(--primary-rgb), 0.25);
}

/* ---------- Section Titles ---------- */
.section-title {
    text-align: center;
    margin-bottom: 44px;
}

.section-title h2 {
    font-size: 34px;
    margin-bottom: 10px;
    letter-spacing: -0.5px;
}

.section-title p {
    color: var(--text-light);
    max-width: 480px;
    margin: 0 auto;
    font-size: 15px;
    line-height: 1.7;
}

/* Decorative line under section title */
.section-title h2::after {
    content: '';
    display: block;
    width: 50px;
    height: 3px;
    background: linear-gradient(90deg, var(--accent), var(--primary));
    margin: 14px auto 0;
    border-radius: 2px;
}

/* ---------- Page Header ---------- */
.page-header {
    background: 
        linear-gradient(135deg, rgba(28, 18, 13, 0.93) 0%, rgba(62, 39, 35, 0.88) 50%, rgba(93, 64, 55, 0.85) 100%);
    color: white;
    padding: 56px 0;
    margin: -48px 0 48px;
    text-align: center;
    position: relative;
    overflow: hidden;
}
.page-header::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: radial-gradient(circle at 20% 50%, rgba(var(--accent-rgb), 0.08), transparent 50%);
}
.page-header::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    height: 60px;
    background: linear-gradient(to top, var(--bg-cream), transparent);
}

.page-header .container { position: relative; z-index: 1; }

.page-header h1 {
    color: white;
    font-size: 38px;
    margin-bottom: 10px;
    animation: fadeInUp 0.6s ease both;
    letter-spacing: -0.5px;
}

.page-header p {
    opacity: 0.8;
    font-size: 16px;
    animation: fadeInUp 0.6s ease 0.1s both;
}

/* ---------- Preview Box ---------- */
.preview-box {
    background: var(--bg-white);
    padding: 28px;
    border-radius: var(--radius-md);
    box-shadow: var(--shadow);
    margin-top: 20px;
    border: 1px solid var(--border);
    word-wrap: break-word;
    overflow-x: auto;
}

.preview-box pre {
    white-space: pre-wrap;
    font-family: 'JetBrains Mono', 'Fira Code', 'Courier New', monospace;
    font-size: 13px;
    line-height: 1.7;
    color: var(--text-body);
}

/* ---------- Encrypted Data Display ---------- */
.encrypted-display {
    background: linear-gradient(160deg, #0f0f1a, #1a1a2e, #16213e);
    color: #00f0ff;
    padding: 28px;
    border-radius: var(--radius-md);
    font-family: 'JetBrains Mono', 'Fira Code', 'Courier New', monospace;
    font-size: 13px;
    line-height: 1.7;
    overflow-x: auto;
    margin-top: 16px;
    border: 1px solid rgba(0, 240, 255, 0.1);
    box-shadow: 0 0 40px rgba(0, 240, 255, 0.05);
}

/* ---------- Breadcrumb ---------- */
.breadcrumb {
    display: flex;
    gap: 10px;
    align-items: center;
    font-size: 13px;
    color: var(--text-light);
    margin-bottom: 28px;
    padding: 12px 20px;
    background: var(--bg-white);
    border-radius: 50px;
    box-shadow: var(--shadow-xs);
    width: fit-content;
}

.breadcrumb a { 
    color: var(--primary); 
    font-weight: 500;
    transition: color var(--transition);
}
.breadcrumb a:hover {
    color: var(--accent);
}
.breadcrumb .separator { 
    color: var(--border); 
    font-size: 10px;
}

/* ---------- Footer ---------- */
.site-footer {
    background: linear-gradient(180deg, var(--bg-dark) 0%, #100a07 100%);
    color: rgba(255,255,255,0.7);
    padding: 64px 0 0;
    margin-top: 48px;
}

.footer-grid {
    display: grid;
    grid-template-columns: 1.5fr 1fr 1fr 1fr;
    gap: 40px;
    padding-bottom: 48px;
    border-bottom: 1px solid rgba(255,255,255,0.08);
}

.footer-col h3 {
    color: var(--accent);
    font-size: 20px;
    margin-bottom: 16px;
}

.footer-col h4 {
    color: rgba(255,255,255,0.9);
    margin-bottom: 18px;
    font-family: var(--font-sans);
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.8px;
    font-size: 12px;
}

.footer-col p {
    font-size: 14px;
    line-height: 1.8;
    margin-bottom: 8px;
}

.footer-col ul {
    list-style: none;
}
.footer-col ul li {
    margin-bottom: 10px;
}
.footer-col ul a {
    color: rgba(255,255,255,0.6);
    font-size: 14px;
    transition: all var(--transition);
    display: inline-flex;
    align-items: center;
    gap: 6px;
}
.footer-col ul a::before {
    content: '\2192';
    font-size: 11px;
    opacity: 0;
    transform: translateX(-8px);
    transition: all var(--transition);
}
.footer-col ul a:hover::before {
    opacity: 1;
    transform: translateX(0);
}
.footer-col ul a:hover {
    color: var(--accent-light);
    padding-left: 4px;
}

.footer-bottom {
    padding: 24px 0;
    text-align: center;
    font-size: 13px;
    color: rgba(255,255,255,0.4);
}

/* ---------- Responsive ---------- */
@media (max-width: 1024px) {
    .footer-grid {
        grid-template-columns: 1fr 1fr;
    }
}

@media (max-width: 768px) {
    :root {
        --header-height: 68px;
    }

    .mobile-toggle { display: flex; }

    .main-nav {
        display: none;
        position: absolute;
        top: var(--header-height);
        left: 0;
        right: 0;
        background: rgba(255, 255, 255, 0.98);
        backdrop-filter: blur(20px);
        -webkit-backdrop-filter: blur(20px);
        border-bottom: 1px solid var(--border);
        box-shadow: var(--shadow-lg);
        padding: 16px;
        animation: slideDown 0.3s ease;
    }
    .main-nav.open { display: block; }
    .main-nav ul { flex-direction: column; gap: 2px; }
    .main-nav a { 
        padding: 14px 18px;
        border-radius: var(--radius);
    }

    .hero { padding: 64px 0; }
    .hero h1 { font-size: 32px; }
    .hero p { font-size: 16px; }
    .page-header h1 { font-size: 28px; }
    .page-header { padding: 44px 0; }

    .featured-article { grid-template-columns: 1fr; }
    .featured-article .card-image { min-height: 200px; }
    .featured-article .card-body { padding: 28px; }
    .featured-article h3 { font-size: 22px; }
    .articles-grid { grid-template-columns: 1fr; }
    .contact-grid { grid-template-columns: 1fr; }
    .profile-info { grid-template-columns: 1fr; }
    .footer-grid { grid-template-columns: 1fr; gap: 32px; }

    .admin-layout { grid-template-columns: 1fr; }
    .admin-sidebar { 
        display: none;
    }
    .admin-content { padding: 24px 16px; }

    .article-content { padding: 28px; }
    .article-header h1 { font-size: 28px; }
    .auth-box { padding: 32px 24px; }
    .section-title h2 { font-size: 28px; }
    .menu-category-title { font-size: 24px; }
    .profile-header { padding: 36px 24px; }
    .profile-body { padding: 28px 20px; }
}

@media (max-width: 480px) {
    .container { padding: 0 16px; }
    .hero h1 { font-size: 26px; }
    .hero { padding: 48px 0; }
    .menu-grid { grid-template-columns: 1fr; }
    .stat-grid { grid-template-columns: 1fr 1fr; }
    .search-box { flex-direction: column; }
    .search-box .btn-primary { width: 100%; }
    .breadcrumb { font-size: 12px; gap: 6px; padding: 10px 16px; }
    .logo-text { font-size: 22px; }
    .card-image { height: 180px; }
    .loyalty-points { font-size: 42px; }
}

/* ---------- Print Styles ---------- */
@media print {
    .site-header, .site-footer, .mobile-toggle,
    .admin-sidebar, .btn-primary, .btn-secondary,
    .comment-form, .search-box { display: none !important; }
    body { background: white; color: black; }
    .article-content { box-shadow: none; border: 1px solid #ddd; }
}
